#!/usr/bin/env node
// Managed by the pi-foundry skill.
// This deploy-time adapter script is copied from the pi-foundry skill adapter bundle.
// Do not edit directly unless debugging the adapter.
// To update, run the pi-foundry skill migration flow.
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { createHash } from "node:crypto";
import { dirname } from "node:path";

const args = new Set(process.argv.slice(2));
const checkOnly = args.has("--check");
const allowAzureOverwrite = args.has("--allow-azure-overwrite") || process.env.PI_FOUNDRY_ALLOW_AZURE_OVERWRITE === "1";
const CONFIG_PATH = ".azd/pi-foundry/pi-foundry.yaml";

function stripComment(value) {
  let quote;
  for (let index = 0; index < value.length; index += 1) {
    const char = value[index];
    if ((char === '"' || char === "'") && value[index - 1] !== "\\") quote = quote === char ? undefined : quote ?? char;
    if (char === "#" && !quote) return value.slice(0, index).trimEnd();
  }
  return value.trimEnd();
}

function unquote(value) {
  const trimmed = stripComment(value).trim();
  if ((trimmed.startsWith('"') && trimmed.endsWith('"')) || (trimmed.startsWith("'") && trimmed.endsWith("'"))) return trimmed.slice(1, -1);
  return trimmed;
}

function yamlScalar(text, dottedPath, fallback) {
  const parts = dottedPath.split(".");
  let indent = -1;
  let offset = 0;

  for (const part of parts) {
    const lines = text.slice(offset).split(/\r?\n/);
    let found;
    let consumed = 0;
    for (const line of lines) {
      const lineIndent = line.match(/^\s*/)?.[0].length ?? 0;
      const match = line.match(/^\s*([A-Za-z0-9_-]+):\s*(.*?)\s*$/);
      if (match && match[1] === part && lineIndent > indent) {
        found = { line, lineIndent, rawValue: match[2] };
        break;
      }
      consumed += line.length + 1;
    }
    if (!found) return fallback;
    indent = found.lineIndent;
    offset += consumed + found.line.length + 1;
    if (part === parts.at(-1)) {
      const value = unquote(found.rawValue);
      return value || fallback;
    }
  }
  return fallback;
}

function yamlList(text, dottedPath, fallback = []) {
  const key = dottedPath.split(".").at(-1);
  const lines = text.split(/\r?\n/);
  for (let index = 0; index < lines.length; index += 1) {
    const match = lines[index].match(/^(\s*)([A-Za-z0-9_-]+):\s*$/);
    if (!match || match[2] !== key) continue;
    const keyIndent = match[1].length;
    const values = [];
    for (let childIndex = index + 1; childIndex < lines.length; childIndex += 1) {
      const child = lines[childIndex];
      if (!child.trim()) continue;
      const childIndent = child.match(/^\s*/)?.[0].length ?? 0;
      if (childIndent <= keyIndent) break;
      const item = child.match(/^\s*-\s+(.*?)\s*$/);
      if (item) values.push(unquote(item[1]));
    }
    return values.length > 0 ? values : fallback;
  }
  return fallback;
}

function boolScalar(text, dottedPath, fallback = false) {
  const value = yamlScalar(text, dottedPath, String(fallback));
  return value === "true" || value === "1";
}

function sha256(content) {
  return createHash("sha256").update(content).digest("hex");
}

function renderDockerfile(config) {
  return `# Generated by pi-foundry. Do not edit directly.\n# Source: .azd/pi-foundry/pi-foundry.yaml\n# Runtime source is not vendored into the user's repo; it comes from a versioned base image.\nARG PI_FOUNDRY_RUNTIME_IMAGE=${config.runtime.image}\nFROM \${PI_FOUNDRY_RUNTIME_IMAGE}\n\nWORKDIR /app\nCOPY . /workspace\n`;
}

function renderAzure(config) {
  return `# Generated by pi-foundry. Do not edit directly.\n# Source: .azd/pi-foundry/pi-foundry.yaml\n# To update, edit the source config or use the pi-foundry deploy skill, then run:\n#   node .azd/pi-foundry/render.mjs\n# yaml-language-server: $schema=https://raw.githubusercontent.com/Azure/azure-dev/main/schemas/v1.0/azure.yaml.json\n\nrequiredVersions:\n  extensions:\n    azure.ai.agents: '>=0.1.0-preview'\nname: ${config.agent.name}\nworkflows:\n  up:\n    - azd: exec -- node .azd/pi-foundry/render.mjs\n    - azd: exec -- node .azd/pi-foundry/render.mjs --check\n    - azd: exec -- node .azd/pi-foundry/doctor.mjs\n    - azd: package --all\n    - azd: deploy --all\n    - azd: exec -- node .azd/pi-foundry/postdeploy.mjs\nservices:\n  ${config.agent.name}:\n    project: .\n    host: azure.ai.agent\n    language: docker\n    docker:\n      path: .azd/pi-foundry/Dockerfile\n      context: .\n      remoteBuild: ${config.docker.remoteBuild}\n      image: ${config.docker.image}\n      tag: ${config.docker.tag}\n    config:\n      container:\n        resources:\n          cpu: "${config.container.cpu}"\n          memory: ${config.container.memory}\n      startupCommand: ${config.runtime.startupCommand}\n`;
}

const envNames = [
  "PI_ARGS",
  "REQUEST_TIMEOUT_MS",
  "ENABLE_DIAGNOSTICS",
  "PI_MOCK",
  "PI_OPENAI_API_KEY",
  "PI_OPENAI_BASE_URL",
  "PI_OPENAI_MODEL",
  "ARTIFACT_PUBLISH_MODE",
  "ARTIFACT_STORAGE_ACCOUNT",
  "ARTIFACT_STATIC_WEB_ENDPOINT",
  "ARTIFACT_STATIC_WEB_CONTAINER",
  "ARTIFACT_BLOB_PREFIX",
];

function renderAgent(config) {
  const env = envNames.map((name) => `  - name: ${name}\n    value: \${${name}}`).join("\n");
  return `# Generated by pi-foundry. Do not edit directly.\n# Source: .azd/pi-foundry/pi-foundry.yaml\n# yaml-language-server: $schema=https://raw.githubusercontent.com/microsoft/AgentSchema/refs/heads/main/schemas/v1.0/ContainerAgent.yaml\nkind: hosted\nname: ${config.agent.name}\nprotocols:\n  - protocol: invocations\n    version: 1.0.0\nimage: example.azurecr.io/${config.docker.image}:${config.docker.tag}\nresources:\n  cpu: "${config.container.cpu}"\n  memory: ${config.container.memory}\nenvironment_variables:\n${env}\n`;
}

function renderManifest(config) {
  const env = envNames.map((name) => `    - name: ${name}\n      value: "{{${name}}}"`).join("\n");
  return `# Generated by pi-foundry. Do not edit directly.\n# Source: .azd/pi-foundry/pi-foundry.yaml\n# yaml-language-server: $schema=https://raw.githubusercontent.com/microsoft/AgentSchema/refs/heads/main/schemas/v1.0/AgentManifest.yaml\nname: ${config.agent.name}\ndisplayName: "${config.agent.displayName}"\ndescription: >\n  ${config.agent.description}\nmetadata:\n  tags:\n    - AI Agent Hosting\n    - Invocations Protocol\n    - Bring Your Own\n    - pi\n    - skill-managed\ntemplate:\n  name: ${config.agent.name}\n  kind: hosted\n  protocols:\n    - protocol: invocations\n      version: 1.0.0\n  image: "{{CONTAINER_IMAGE}}"\n  environment_variables:\n${env}\n`;
}

function renderLock(config, files) {
  return `# Generated by pi-foundry. Do not edit directly.\nversion: 1\nadapterVersion: 0.1.0\nruntimeImage: ${config.runtime.image}\ngenerated:\n${Object.entries(files).map(([path, content]) => `  ${path}: sha256:${sha256(content)}`).join("\n")}\n`;
}

async function readConfig() {
  let text;
  try {
    text = await readFile(CONFIG_PATH, "utf8");
  } catch {
    throw new Error(`${CONFIG_PATH} not found. Use the pi-foundry skill to initialize this adapter, or run the skill update-config script to create it.`);
  }
  return {
    agent: {
      name: yamlScalar(text, "agent.name", "pi-agent"),
      displayName: yamlScalar(text, "agent.displayName", "Pi Agent"),
      description: yamlScalar(text, "agent.description", "Foundry Hosted Agent deployment adapter for an existing Pi agent repo."),
    },
    runtime: {
      image: yamlScalar(text, "runtime.image", "crce6hg4ngzj3as.azurecr.io/pi-foundry-runtime:0.1.0"),
      startupCommand: yamlScalar(text, "runtime.startupCommand", "/app/runtime/official-invocations/entrypoint.sh"),
    },
    container: {
      cpu: yamlScalar(text, "container.cpu", "2"),
      memory: yamlScalar(text, "container.memory", "4Gi"),
    },
    docker: {
      image: yamlScalar(text, "docker.image", yamlScalar(text, "agent.name", "pi-agent")),
      tag: yamlScalar(text, "docker.tag", "latest"),
      remoteBuild: boolScalar(text, "docker.remoteBuild", true),
    },
    pi: {
      args: yamlList(text, "pi.args", ["--mode", "rpc", "--no-session"]),
    },
  };
}

function isPiFoundryManagedAzure(text) {
  return text.includes("Generated by pi-foundry") || text.includes("pi-foundry bootstrap azd file") || text.includes(".azd/pi-foundry/pi-foundry.yaml");
}

async function writeIfChanged(path, content) {
  await mkdir(dirname(path), { recursive: true });
  try {
    const existing = await readFile(path, "utf8");
    if (existing === content) return false;
    if (path === "azure.yaml" && !allowAzureOverwrite && !isPiFoundryManagedAzure(existing)) {
      throw new Error("azure.yaml already exists and is not pi-foundry-managed. Ask the user before replacing it, then rerun with --allow-azure-overwrite or PI_FOUNDRY_ALLOW_AZURE_OVERWRITE=1.");
    }
  } catch (error) {
    if (error?.code !== "ENOENT") throw error;
    // File does not exist yet.
  }
  await writeFile(path, content);
  return true;
}

async function assertUnchanged(path, expected) {
  let actual;
  try {
    actual = await readFile(path, "utf8");
  } catch {
    throw new Error(`${path} is missing; run: node .azd/pi-foundry/render.mjs`);
  }
  if (actual !== expected) throw new Error(`${path} is out of date; run: node .azd/pi-foundry/render.mjs`);
}

async function main() {
  const config = await readConfig();
  const files = {
    "azure.yaml": renderAzure(config),
    ".azd/pi-foundry/Dockerfile": renderDockerfile(config),
    ".azd/pi-foundry/generated/agent.yaml": renderAgent(config),
    ".azd/pi-foundry/generated/agent.manifest.yaml": renderManifest(config),
  };
  const lock = renderLock(config, files);

  if (checkOnly) {
    for (const [path, content] of Object.entries(files)) await assertUnchanged(path, content);
    await assertUnchanged(".azd/pi-foundry/pi-foundry.lock.yaml", lock);
    console.log("pi-foundry generated files are up to date");
  } else {
    const changed = [];
    for (const [path, content] of Object.entries(files)) {
      if (await writeIfChanged(path, content)) changed.push(path);
    }
    if (await writeIfChanged(".azd/pi-foundry/pi-foundry.lock.yaml", lock)) changed.push(".azd/pi-foundry/pi-foundry.lock.yaml");
    if (changed.length === 0) console.log("pi-foundry generated files already up to date");
    else console.log(`pi-foundry rendered: ${changed.join(", ")}`);
  }
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exitCode = 1;
});
